import { calculatePartnerPayout } from "./revenueSharing";

describe("calculatePartnerPayout", () => {
  // AC3: canonical example — $100 transaction, 5% platform fee, 70% partner share
  it("AC3: returns $66.50 for $100 transaction, 5% platform fee, 70% partner share", () => {
    // platform_fee = $100 * 0.05 = $5.00
    // net          = $100 - $5   = $95.00
    // payout       = $95 * 0.70  = $66.50
    expect(calculatePartnerPayout(100, 0.05, 0.70)).toBe(66.50);
  });

  // AC1: formula — payout = (transactionAmount - platform_fee_amount) * partnerSharePercentage
  it("AC1: applies the correct formula (net of fee × partner share)", () => {
    // transaction $200, fee 10%, share 50%
    // fee = $20, net = $180, payout = $90
    expect(calculatePartnerPayout(200, 0.10, 0.50)).toBe(90.00);
  });

  // AC2: platform fee amount = transaction * platform_fee_percentage
  it("AC2: computes platform fee as transaction_amount * platform_fee_percentage", () => {
    // We can verify by checking a case where fee removes a known dollar amount.
    // $50 transaction, 20% fee → fee = $10, net = $40, 100% share → payout = $40
    expect(calculatePartnerPayout(50, 0.20, 1.0)).toBe(40.00);
  });

  // AC4: floor rounding — fractional cents must be rounded DOWN, not half-up
  it("AC4: floors fractional cents (does NOT round half-up)", () => {
    // $100, 0% platform fee, 2/3 partner share → $66.6666... → should floor to $66.66
    const payout = calculatePartnerPayout(100, 0, 2 / 3);
    expect(payout).toBe(66.66);
  });

  it("AC4: floors when result would have been rounded up by half-up rounding", () => {
    // $10, 0% fee, 1/3 share → $3.3333... → floor to $3.33, NOT $3.34
    const payout = calculatePartnerPayout(10, 0, 1 / 3);
    expect(payout).toBe(3.33);
  });

  // AC5: zero transaction amount returns zero payout
  it("AC5: returns 0 when transactionAmount is 0", () => {
    expect(calculatePartnerPayout(0, 0.05, 0.70)).toBe(0);
  });

  it("AC5: returns 0 when transactionAmount is 0 regardless of fee/share percentages", () => {
    expect(calculatePartnerPayout(0, 0, 0)).toBe(0);
    expect(calculatePartnerPayout(0, 1.0, 1.0)).toBe(0);
  });

  // Edge: exact-cent results are not disturbed by floor
  it("returns exact cents without distortion when result has no fractional cents", () => {
    // $1000, 5% fee, 70% share → fee=$50, net=$950, payout=$665.00
    expect(calculatePartnerPayout(1000, 0.05, 0.70)).toBe(665.00);
  });

  // Edge: zero platform fee passes full amount to partner share calculation
  it("applies no deduction when platformFeePercentage is 0", () => {
    // $200, 0% fee, 50% share → payout = $100
    expect(calculatePartnerPayout(200, 0, 0.50)).toBe(100.00);
  });

  // Edge: zero partner share always yields zero payout
  it("returns 0 when partnerSharePercentage is 0", () => {
    expect(calculatePartnerPayout(100, 0.05, 0)).toBe(0);
  });
});

